patch:
--- a/priority_encoder.v
+++ b/priority_encoder.v
@@ -9,7 +9,7 @@
   output [3:0] priority_out
 );

-  always @(request_bits or valid_mask)
+  always @(request_bits or valid_mask or grant_enable)
   begin
     if (grant_enable == 1'b0)
       priority_out = 4'h0;

before_code:
module priority_encoder_16bit (
  input [15:0] request_bits,
  input [15:0] valid_mask,
  input grant_enable,
  output [3:0] priority_out
);

  always @(request_bits or valid_mask)
  begin
    if (grant_enable == 1'b0)
      priority_out = 4'h0;
    else if (request_bits & valid_mask[0])
      priority_out = 4'd0;
    else if (request_bits & valid_mask[1])
      priority_out = 4'd1;
    else
      priority_out = 4'hf;
  end

endmodule

after_code:
module priority_encoder_16bit (
  input [15:0] request_bits,
  input [15:0] valid_mask,
  input grant_enable,
  output [3:0] priority_out
);

  always @(request_bits or valid_mask or grant_enable)
  begin
    if (grant_enable == 1'b0)
      priority_out = 4'h0;
    else if (request_bits & valid_mask[0])
      priority_out = 4'd0;
    else if (request_bits & valid_mask[1])
      priority_out = 4'd1;
    else
      priority_out = 4'hf;
  end

endmodule
